#include<bits/stdc++.h>
using namespace std;
int n, ans = 0, m, k, g;
struct node {
	int x, y;
} a[5005];
bool cmp(node a, node b) {
    if(a.y==b.y) return a.x<b.x;
	return a.y > b.y;
}
int main() {
	cin >> n >> m;
	for (int i = 1; i <= n; i++) cin >> a[i].x >> a[i].y;
	sort(a + 1, a + n + 1, cmp);
	k = a[int(floor(m*1.5))].y;
	for (int i = 1; i <= n; i++) {
		if (a[i].y >= k) {
			ans = a[i].y;
			g++;
		}
	}
	cout << ans <<" "<< g << "\n";
	for (int i = 1; i <= n; i++) {
		if (a[i].y >= k) {
			cout << a[i].x << " " << a[i].y<<"\n";
		}
	}
	return 0;
}
